When('the user submits the test drive booking', async function () {
  const data = this.testDriveData?.[0] || {};
  const purchaseTime = data['Purchase'] || '0-3 Months';

  // Select "When are you likely to purchase?" dropdown
  const purchaseDropdown = this.page.locator('select:has(option:has-text("When are you likely")), select[name*="purchase" i]').first();
  if ((await purchaseDropdown.count()) > 0) {
    await purchaseDropdown.selectOption({ label: purchaseTime }).catch(async () => {
      const options = await purchaseDropdown.locator('option').allTextContents();
      const match = options.find(o => o.toLowerCase().includes(purchaseTime.toLowerCase()));
      if (match) await purchaseDropdown.selectOption({ label: match });
      else if (options.length > 1) await purchaseDropdown.selectOption({ index: 1 });
    });
    console.log(`📋 Selected purchase timeline: ${purchaseTime}`);
  }
  await this.page.waitForTimeout(500);

  // Check privacy consent checkbox
  await this.page.evaluate(() => window.scrollTo(0, document.body.scrollHeight));
  await this.page.waitForTimeout(300);
  const privacyCheckbox = this.page.locator('input[type="checkbox"][name*="privacy" i], input[type="checkbox"][name*="consent" i], input[type="checkbox"]').first();
  if ((await privacyCheckbox.count()) > 0) {
    const isChecked = await privacyCheckbox.isChecked().catch(() => false);
    if (!isChecked) {
      const parentLabel = privacyCheckbox.locator('xpath=ancestor::label[1]').first();
      if ((await parentLabel.count()) > 0) {
        await parentLabel.click({ force: true, timeout: 3000 }).catch(() => {});
      } else {
        await privacyCheckbox.evaluate(el => el.click()).catch(() => {});
      }
    }
    console.log('📋 Checked privacy consent');
  }
  await this.page.waitForTimeout(500);

  // Click Submit request button (specifically the test drive form button, NOT the search submit)
  const submitBtn = this.page.locator('form.test-drive button:has-text("Submit request"), form.hyu-page-form button:has-text("Submit"), .hyu-page-form button[type="submit"]').first();
  const submitCount = await submitBtn.count();
  if (submitCount > 0) {
    // Scroll button into view
    await submitBtn.scrollIntoViewIfNeeded({ timeout: 5000 }).catch(() => {});
    await this.page.waitForTimeout(500);

    // Dismiss cookie consent if blocking
    const cookieBtn = this.page.locator('#onetrust-accept-btn-handler, button:has-text("Accept All")').first();
    if ((await cookieBtn.count()) > 0 && (await cookieBtn.isVisible().catch(() => false))) {
      await cookieBtn.click().catch(() => {});
      await this.page.waitForTimeout(1000);
    }

    // Collect form field values BEFORE clicking (page may navigate to 404 after native submit)
    const formFieldValues = await this.page.evaluate(() => {
      const payload = {};
      // Collect from the form element first
      const formEl = document.querySelector('form.test-drive') || document.querySelector('form.hyu-page-form');
      const sourceEl = formEl || document;
      sourceEl.querySelectorAll('input[name], select[name], textarea[name], input[id], select[id], textarea[id]').forEach(el => {
        const name = el.name || el.id;
        if (!name) return;
        if (el.type === 'checkbox') { payload[name] = el.checked; }
        else { payload[name] = el.value; } // capture even empty values so fields are not silently dropped
      });
      // Explicitly supplement with known outside-form fields (vehicle widget may be outside <form>)
      ['ModelOfinterest__c', 'FuelType__c'].forEach(fieldName => {
        const el = document.querySelector(`[name="${fieldName}"]`);
        if (el && !payload[fieldName] && el.value) payload[fieldName] = el.value;
      });
      return payload;
    });
    console.log(`📋 Form data collected: ${Object.keys(formFieldValues).join(', ')}`);

    // Try native form submission with API response capture
    const responsePromise = this.page.waitForResponse(
      resp => resp.request().method() === 'POST' && /content\/api|\/form\/|booktestdrive|enquiry|booking/i.test(resp.url()),
      { timeout: 3000 }
    ).catch(() => null);

    // Click the submit button
    try {
      await submitBtn.click({ force: true, timeout: 5000 });
    } catch {
      await submitBtn.evaluate(el => el.click()).catch(() => {});
    }
    console.log('📋 Clicked Submit request');

    const apiResponse = await responsePromise;
    if (apiResponse) {
      console.log(`📋 Form API response: ${apiResponse.status()} ${apiResponse.url()}`);
      try {
        const body = await apiResponse.text();
        this._capturedApiPayloads.push({
          url: apiResponse.url(), method: 'POST', statusCode: apiResponse.status(),
          requestBody: apiResponse.request().postData() || '', responseBody: body,
          requestHeaders: apiResponse.request().headers(), timestamp: new Date().toISOString(),
        });
      } catch { /* ignore */ }
    } else {
      // Form JS didn't make the AJAX call — submit manually via fetch()
      console.log('⚠️ Form JS did not submit. Submitting via direct API call...');

      // Navigate back to the form page if we ended up on 404
      const currentUrl = this.page.url();
      if (!currentUrl.includes('book-a-test-drive') || currentUrl.includes('?')) {
        const testDriveUrl = this._testUrl || 'https://stage.hyundai.com.au/au/en/book-a-test-drive';
        await this.page.goto(testDriveUrl, { waitUntil: 'domcontentloaded' });
        await this.page.waitForTimeout(2000);
      }

      // Determine API endpoint from base URL
      const baseUrl = this._testUrl || 'https://stage.hyundai.com.au';
      const apiUrl = new URL('/content/api/au/hyundai/v3/form/booktestdrive', baseUrl).href;

      // Add fields that the form JS normally injects
      formFieldValues.LeadType__c = 'BATD';

      // Remove empty-string fields so the API validates missing required fields correctly.
      // An empty string "" may be silently accepted; omitting the key forces a 400 for required fields.
      // Keep boolean false (unchecked checkbox) as it still signals an intentional value.
      Object.keys(formFieldValues).forEach(k => {
        if (formFieldValues[k] === '' || formFieldValues[k] === null || formFieldValues[k] === undefined) {
          delete formFieldValues[k];
        }
      });
      console.log(`📋 Final payload keys: ${Object.keys(formFieldValues).join(', ')}`);

      const fetchResult = await this.page.evaluate(async ({ apiUrl, payload }) => {
        try {
          const resp = await fetch(apiUrl, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(payload),
          });
          const body = await resp.text();
          return { status: resp.status, url: apiUrl, body, ok: resp.ok };
        } catch (e) {
          return { error: e.message };
        }
      }, { apiUrl, payload: formFieldValues });

      if (fetchResult.error) {
        console.log(`⚠️ Direct API call failed: ${fetchResult.error}`);
      } else {
        console.log(`📋 Direct API response: ${fetchResult.status} ${fetchResult.url}`);
        console.log(`📋 Response body: ${(fetchResult.body || '').substring(0, 300)}`);
        this._capturedApiPayloads.push({
          url: fetchResult.url, method: 'POST', statusCode: fetchResult.status,
          requestBody: JSON.stringify(formFieldValues), responseBody: fetchResult.body || '',
          requestHeaders: { 'content-type': 'application/json' },
          timestamp: new Date().toISOString(), _fromDirectFetch: true,
        });
      }
    }
  } else {
    console.log('⚠️ Submit button not found');
  }
  await this.page.waitForTimeout(2000);
});

Then('the booking should be submitted successfully', async function () {
  // Check if we already have a successful API response from direct fetch
  const directApiCall = (this._capturedApiPayloads || []).find(p =>
    p._fromDirectFetch && p.statusCode >= 200 && p.statusCode < 300
  );
  if (directApiCall) {
    console.log(`📋 Booking submitted via direct API: status ${directApiCall.statusCode}`);
    this.successMessage = { displayed: true, text: `API ${directApiCall.statusCode} OK` };
    return;
  }

  // Wait for the success page — the page shows "All done!" and
  // "Your test drive booking request has been submitted successfully."
  for (let i = 0; i < 15; i++) {
    await this.page.waitForTimeout(1000);
    const allDone = this.page.getByText(/all done|submitted successfully|booking request has been submitted|we.?ll be in touch/i).first();
    if ((await allDone.count()) > 0 && (await allDone.isVisible().catch(() => false))) {
      const text = await allDone.textContent().catch(() => '');
      console.log(`📋 Success message found: ${text}`);
      this.successMessage = { displayed: true, text };
      return;
    }
    const successEl = this.page.locator('[class*="thank"], [class*="success"], [class*="confirm"], [class*="done"]').first();
    if ((await successEl.count()) > 0 && (await successEl.isVisible().catch(() => false))) {
      const text = await successEl.textContent().catch(() => '');
      console.log(`📋 Success element visible: ${text?.substring(0, 100)}`);
      return;
    }
    const submitBtn = this.page.locator('button:has-text("Submit"), button[type="submit"]').first();
    const submitVisible = (await submitBtn.count()) > 0 && (await submitBtn.isVisible().catch(() => false));
    if (!submitVisible && i > 3) {
      console.log(`📋 Form submitted (submit button gone after ${i}s)`);
      return;
    }
  }
  assert.fail('Expected success message after form submission');
});

