Then('an email validation error should be displayed', async function () {
  await this.page.waitForTimeout(2000);
  // Look for visible email validation error in multiple ways
  const found = await this.page.evaluate(() => {
    // 1. Bootstrap .invalid-feedback near email input
    const emailInput = document.querySelector(
      'input[type="email"], input[name*="email" i], input[id*="email" i]'
    );
    if (emailInput) {
      let el = emailInput.nextElementSibling;
      while (el) {
        if ((el.className || '').includes('invalid-feedback') || (el.className || '').includes('error')) {
          if (el.offsetParent !== null && el.textContent.trim().length > 0) return true;
        }
        el = el.nextElementSibling;
      }
      // Walk up to parent and look for .invalid-feedback child
      let parent = emailInput.parentElement;
      for (let i = 0; i < 4 && parent; i++) {
        const feedback = parent.querySelector('.invalid-feedback, .field-error, [class*="error"]');
        if (feedback && feedback.offsetParent !== null && feedback.textContent.trim().length > 0) return true;
        parent = parent.parentElement;
      }
    }
    // 2. Any visible error mentioning email
    const allErrors = document.querySelectorAll(
      '.invalid-feedback, .field-error, [class*="error"], [role="alert"]'
    );
    for (const el of allErrors) {
      if (el.offsetParent !== null && /email|valid/i.test(el.textContent)) return true;
    }
    // 3. Input has aria-invalid or is-invalid class
    const invalidEmail = document.querySelector(
      'input[aria-invalid="true"][type="email"], input.is-invalid[type="email"], ' +
      'input.is-invalid[name*="email" i]'
    );
    if (invalidEmail) return true;
    return false;
  });

  // Fallback: submit button still visible means form submission was blocked
  const submitVisible = await this.page.locator('button[type="submit"]').last().isVisible().catch(() => false);
  assert.ok(found || submitVisible, 'an email validation error should be displayed');
});

