Then('no vehicle or dealer should be selected', async function () {
  await this.page.waitForTimeout(1000);
  const content = await this.page.content();
  console.log(`📋 Step: no vehicle or dealer should be selected`);
  assert.ok(content.length > 0, 'no vehicle or dealer should be selected');
});
